sparql:
SELECT ?month WHERE {
  wd:Q14269987 wdt:P585 ?eventDate .
  BIND(MONTH(?eventDate) AS ?month)
}

SELECT(COUNT(*) AS ?count) WHERE {
  wd:Q1971533 wdt:P710 ?cyclist .
  ?cyclist wdt:P2781 ?time_diff .
  FILTER(?time_diff < "PT30M" ^^ xsd:duration)
  ?cyclist wdt:P802 ?grand_tour .
  VALUES ?grand_tour {
    wd:Q3717 wd:Q371445 wd:Q112253
  }
  ?cyclist wdt:P1042 ?placement .
  FILTER(?placement <= 10)
}

SELECT ?inception ?dissolved WHERE {
  wd:Q1432490 wdt:P571 ?inception .
  wd:Q1432490 wdt:P576 ?dissolved .
}

SELECT ?schoolLabel WHERE {
  wd:Q4637473 wdt:P1346 wd:Q11655946 .
  wd:Q11655946 rdfs:label ?schoolLabel .
  FILTER(LANG(?schoolLabel) = 'en')
}

SELECT ?film WHERE {
  ?film wdt:P57 wd:Q489831 .
  ?film wdt:P577 ?year .
}
ORDER BY ASC(?year)
LIMIT 1

SELECT(COUNT(*) AS ?count) WHERE {
  wd:Q0 wdt:P162 wd:Q0 .
  ?song wdt:P162 wd:Q0 ; wdt:P1056 ?artist .
  ?artist wdt:P5614 ?awardNominations .
}

SELECT DISTINCT ?country ?area WHERE {
  wd:Q183 wdt:P2046 ?area ; rdfs:label ?country .
  FILTER(LANG(?country) = 'en')
}

SELECT ?teamLabel WHERE {
  wd:Q192083 rdfs:label ?teamLabel
  FILTER(LANG(?teamLabel) = 'en')
  FILTER(CONTAINS(LCASE(?teamLabel) , 'flyers'))
}

SELECT ?ownerLabel WHERE {
  wd:Q169985 wdt:P127 ?owner .
  ?owner rdfs:label ?ownerLabel .
  FILTER(LANG(?ownerLabel) = 'en')
}

SELECT(SUM(IF(?party = wd:Q29468 , 1 , 0)) AS ?republican_count)(SUM(IF(?party = wd:Q35887 , 1 , 0)) AS ?democrat_count) WHERE {
  ?person wdt:P1335 wd:Q4635787 .
  ?person wdt:P102 ?party .
  FILTER(?party IN(wd:Q29468 , wd:Q35887))
}

SELECT ?countryLabel WHERE {
  wd:Q696794 wdt:P17 ?country .
  ?country rdfs:label ?countryLabel .
  FILTER(LANG(?countryLabel) = 'en')
}

SELECT ?locationLabel WHERE {
  wd:Q749718 wdt:P131 ?location .
  ?location rdfs:label ?locationLabel .
  FILTER(LANGMATCHES(LANG(?locationLabel) , 'en'))
}

SELECT(COUNT(*) AS ?count) WHERE {
  wd:Q234758 wdt:P1344 ?event .
  ?event wdt:P1650 wd:Q9352235 .
  ?event p:P1344 ?participation .
  ?participation pq:P1545 wd:Q1229261 .
}

SELECT(COUNT(DISTINCT ?season) AS ?count) WHERE {
  ?season wdt:P1545 wd:Q326859 ; wd:P1415 wd:Q54988 .
}

SELECT(COUNT(?state) AS ?count) WHERE {
  ?state wdt:P31 wd:Q197480 .
  ?state wdt:P17 wd:Q30
}

SELECT(COUNT(DISTINCT ?medalStatement) AS ?goldCount) WHERE {
  ?athlete wdt:P19 wd:Q121157 ; wdt:P106 wd:Q12658 ; wdt:P27 wd:Q30 .
  ?athlete p:P166 ?medalStatement .
  ?medalStatement ps:P166 wd:Q6154310 .
  ?medalStatement pq:P808 wd:Q2454767 .
}

SELECT ?child ?childLabel WHERE {
  ?child wdt:P22 wd:Q223419 .
  ?child rdfs:label ?childLabel .
  FILTER(LANG(?childLabel) = 'en')
}

SELECT DISTINCT ?name WHERE {
  wd:Q172742 rdfs:label ?name
  FILTER(LANG(?name) = 'en')
}

SELECT DISTINCT ?label WHERE {
  ?court wdt:P17 wd:Q35 ; rdfs:label ?label .
  FILTER(LANG(?label) = 'en' && CONTAINS(STR(?label) , 'bankruptcy'))
}

SELECT(COUNT(DISTINCT ?island) AS ?count) WHERE {
  ?island wdt:P31 wd:Q445655 ; wdt:P131 wd:Q168243 ; wdt:P1082 ?population .
  FILTER(?population > 0)
}

SELECT ?game ?gameLabel WHERE {
  ?game wdt:P31 wd:Q7889 ; rdfs:label ?gameLabel ; wdt:P577 ?date .
  FILTER(langMatches(lang(?gameLabel) , "en"))
  FILTER(CONTAINS(LCASE(?gameLabel) , "elite force"))
  FILTER(YEAR(?date) = 1999)
}

SELECT(SUM(?population) AS ?totalPopulation) WHERE {
  ?province wdt:P131 wd:Q806550 .
  ?province wdt:P1082 ?population .
}

SELECT ?locationLabel WHERE {
  wd:Q324497 wdt:P159 ?location .
  ?location rdfs:label ?locationLabel .
  FILTER(lang(?locationLabel) = "en")
  .
}

SELECT(COUNT(?location) AS ?count) WHERE {
  ?game wdt:P170 wd:Q4048789 ; wdt:P31 wd:Q7889 ; wdt:P755 ?location .
}

SELECT ?population WHERE {
  wd:Q35 p:P1082 ?population_statement .
  ?population_statement ps:P1082 ?population .
  ?population_statement pq:P585 ?date .
  FILTER(STRSTARTS(STR(?date) , "2019"))
}

SELECT ?conferenceLabel WHERE {
  wd:Q5916446 wdt:P118 ?conference .
  ?conference rdfs:label ?conferenceLabel .
  FILTER(LANG(?conferenceLabel) = 'en')
}

SELECT ?population WHERE {
  wd:Q486306 p:P1082 ?statement .
  ?statement ps:P1082 ?population .
  ?statement pq:P585 ?date .
  FILTER(year(?date) = 2010)
}

SELECT(COUNT(DISTINCT ?championship) AS ?count) WHERE {
  wd:Q814738 wdt:P118 ?stadium .
  ?stadium wdt:P1082 66161 .
  wd:Q814738 wdt:P2371 ?championship
}

SELECT(COUNT(?medal) AS ?count) WHERE {
  ?athlete wdt:P21 wd:Q6581072 ; wdt:P27 wd:Q38 ; wdt:P166 ?medal .
}
GROUP BY ?athlete
ORDER BY DESC(?count)
LIMIT 1

SELECT ?regionLabel WHERE {
  wd:Q740845 wdt:P131 ?district .
  ?district wdt:P131 ?region .
  ?region rdfs:label ?regionLabel .
  FILTER(LANGMATCHES(LANG(?regionLabel) , 'en'))
}

SELECT(COUNT(DISTINCT ?state) AS ?count) WHERE {
  wd:Q1055811 wdt:P150 ?station .
  ?station wdt:P276 ?city .
  ?city wdt:P131 ?state .
}
